Here's how to handle each scenario with modern MSTest (3.9+/3.10+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class MixedScenarioTests
{
    private readonly TestContext _testContext;
    private string? _tempFilePath;

    public MixedScenarioTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only: skipped on Linux/macOS
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Microsoft.Win32.Registry.GetValue(
            @"HKEY_LOCAL_MACHINE\SOFTWARE\Microsoft\Windows NT\CurrentVersion",
            "ProductName", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void GpuRender_ProducesExpectedOutput()
    {
        var result = GpuRenderer.Render(scene);
        Assert.IsNotNull(result);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await WeatherClient.GetForecastAsync(
            "Seattle", _testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Temp file cleanup — [TestCleanup] runs even on failure
    [TestMethod]
    public void Export_WritesToTempFile()
    {
        _tempFilePath = Path.Combine(Path.GetTempPath(), $"{Guid.NewGuid()}.tmp");
        File.WriteAllText(_tempFilePath, "data");

        var content = File.ReadAllText(_tempFilePath);
        Assert.AreEqual("data", content);
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFilePath is not null && File.Exists(_tempFilePath))
        {
            File.Delete(_tempFilePath);
        }
    }
}
```

**Summary of attributes:**

| Scenario | Attribute | Minimum Version |
|----------|-----------|-----------------|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | MSTest 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | MSTest 3.10+ |
| Flaky retry | `[Retry(3)]` | MSTest 3.9+ |
| Cleanup on failure | `[TestCleanup]` method | Any MSTest |

**Key points:**
- `[OSCondition]` and `[CICondition]` **skip** (not fail) when conditions aren't met.
- `[Retry]` should only be used for genuinely external flakiness — not to mask race conditions.
- `[TestCleanup]` always runs after each test, even on failure or exception, making it ideal for resource cleanup.
- Pair `[Retry]` with `[Timeout]` so a hung request doesn't block indefinitely.
